definitions.evidence:
struct {
          SignatureScheme algorithm;
          opaque signature<0..2^16-1>;
      } CertificateVerify;

The algorithm field specifies the signature algorithm used

struct {
          DistinguishedName authorities<3..2^16-1>;
      } CertificateAuthoritiesExtension;

authorities:  A list of the distinguished names [X501] of acceptable
      certificate authorities, represented in DER-encoded [X690] format.

enum {
          ...
          bad_certificate(42),
...
      } AlertDescription;

bad_certificate:  A certificate was corrupt, contained signatures
      that did not verify correctly, etc.

enum {
          ...
          bad_record_mac(20),
...
      } AlertDescription;

bad_record_mac:  This alert is returned if a record is received which
      cannot be deprotected.

struct {
          PskIdentity identities<7..2^16-1>;
          PskBinderEntry binders<33..2^16-1>;
      } OfferedPsks;

struct {
          opaque certificate_extension_oid<1..2^8-1>;
          opaque certificate_extension_values<0..2^16-1>;
      } OIDFilter;

struct {
          opaque certificate_extension_oid<1..2^8-1>;
          opaque certificate_extension_values<0..2^16-1>;
      } OIDFilter;

enum {
          close_notify(0),
...
      } AlertDescription;

close_notify:  This alert notifies the recipient that the sender will
      not send any more messages on this connection.

struct {
          AlertLevel level;
          AlertDescription description;
      } Alert;

struct {
        ExtensionType extension_type;
        opaque extension_data<0..2^16-1>;
    } Extension;

Here:

-  "extension_data" contains information specific to the particular extension type.

